const body = $input.first().json.body;

let jql;
if (body.customJql && body.customJql.trim()) {
  jql = body.customJql.trim();
} else {
  const project = body.project;
  const issueTypes = body.issueTypes || ['User Story', 'Задача', 'Ошибка', 'Техдолг'];
  const dateFrom = body.dateFrom;
  const dateTo = body.dateTo;
  const typesList = issueTypes.map(t => '"' + t + '"').join(', ');
  jql = 'project = "' + project + '" AND issuetype in (' + typesList + ')';
  if (dateFrom && dateTo) {
    jql += ' AND (statusCategory != Done OR (resolved >= "' + dateFrom + '" AND resolved <= "' + dateTo + '"))';
  } else if (dateFrom) {
    jql += ' AND (statusCategory != Done OR resolved >= "' + dateFrom + '")';
  } else if (dateTo) {
    jql += ' AND (statusCategory != Done OR resolved <= "' + dateTo + '")';
  }
  if (body.extraConditions && body.extraConditions.trim()) {
    jql += ' AND ' + body.extraConditions.trim();
  }
  jql += ' ORDER BY created ASC';
}

return [{ json: { jql, ...body } }];

const issues = [];

for (const item of $input.all()) {
  const issue = item.json;
  const histories = (issue.changelog && issue.changelog.histories) ? issue.changelog.histories : [];

  const sortedHistories = [...histories].sort((a, b) => new Date(a.created) - new Date(b.created));

  const transitions = [];

  if (sortedHistories.length > 0) {
    const firstStatusChange = sortedHistories[0].items && sortedHistories[0].items.find(i => i.field === 'status');
    if (firstStatusChange) {
      transitions.push({
        status: firstStatusChange.fromString,
        enteredAt: issue.fields && issue.fields.created
      });
    }
  } else {
    transitions.push({
      status: issue.fields && issue.fields.status && issue.fields.status.name,
      enteredAt: issue.fields && issue.fields.created
    });
  }

  for (const history of sortedHistories) {
    for (const change of (history.items || [])) {
      if (change.field === 'status') {
        transitions.push({
          status: change.toString,
          enteredAt: history.created
        });
      }
    }
  }

  issues.push({
    key: issue.key,
    summary: (issue.fields && issue.fields.summary) || '',
    type: (issue.fields && issue.fields.issuetype && issue.fields.issuetype.name) || 'Unknown',
    created: (issue.fields && issue.fields.created) || '',
    currentStatus: (issue.fields && issue.fields.status && issue.fields.status.name) || '',
    statusCategory: (issue.fields && issue.fields.status && issue.fields.status.statusCategory && issue.fields.status.statusCategory.key) || undefined,
    resolution: (issue.fields && issue.fields.resolution && issue.fields.resolution.name) || undefined,
    transitions
  });
}

return [{ json: { issues, meta: { total: issues.length, fetchedAt: new Date().toISOString() } } }];
